import{_ as t,o as n,c as a,a2 as r}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"OpenSIN-Bridge Monetization","description":"","frontmatter":{},"headers":[],"relativePath":"bridges/opensin-bridge-monetization.md","filePath":"bridges/opensin-bridge-monetization.md"}'),i={name:"bridges/opensin-bridge-monetization.md"};function o(s,e,d,l,h,c){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="opensin-bridge-monetization" tabindex="-1">OpenSIN-Bridge Monetization <a class="header-anchor" href="#opensin-bridge-monetization" aria-label="Permalink to &quot;OpenSIN-Bridge Monetization&quot;">​</a></h1><p><strong>OpenSIN-Bridge</strong> operates on a Thin-Client / Server-Brain architecture to protect intellectual property and enforce SaaS subscriptions.</p><h2 id="pricing-model" tabindex="-1">Pricing Model <a class="header-anchor" href="#pricing-model" aria-label="Permalink to &quot;Pricing Model&quot;">​</a></h2><ul><li><strong>Free Install:</strong> Extension can be installed for free from the Chrome Web Store.</li><li><strong>OpenSIN Pro (5 EUR/month):</strong> Unlocks all autonomous capabilities (e.g., A2A-SIN-Worker-Prolific integration).</li></ul><h2 id="why-this-architecture" tabindex="-1">Why This Architecture? <a class="header-anchor" href="#why-this-architecture" aria-label="Permalink to &quot;Why This Architecture?&quot;">​</a></h2><p>Chrome Extensions are client-side JavaScript. To prevent cloning and reverse-engineering, <strong>Zero Business Logic</strong> exists in the extension. The extension is merely a DOM-extractor and action-executor. All LLM decisions, anti-detection mechanisms, and persona configurations live on our secure Cloudflare Workers backend.</p><h2 id="the-a2a-sin-stripe-integration" tabindex="-1">The A2A-SIN-Stripe Integration <a class="header-anchor" href="#the-a2a-sin-stripe-integration" aria-label="Permalink to &quot;The A2A-SIN-Stripe Integration&quot;">​</a></h2><p>Instead of handling Stripe events directly in the Cloudflare Worker, we leverage our dedicated <strong>A2A-SIN-Stripe</strong> agent.</p><ol><li>User upgrades to Pro via the extension popup -&gt; Stripe Checkout.</li><li>Stripe Webhook fires on successful payment.</li><li><strong>A2A-SIN-Stripe</strong> catches the webhook, validates the payment, and securely updates the user&#39;s subscription status in our central <strong>Supabase</strong> database.</li><li>The Cloudflare Worker validates the JWT against Supabase on every API call to ensure the user has an active Pro plan.</li></ol><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code> statt npm</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr><tr><td><strong>Test-Beweis-Pflicht</strong></td><td>0.0</td><td>KEIN &quot;Done&quot; ohne echten Test-Lauf</td></tr></tbody></table><p>→ <a href="/best-practices/code-quality.html">Alle Mandate</a></p>',13)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
